MATCH (op:OPERATIONS)
WHERE op.location[1] ENDS WITH 'bad.c' AND toInteger(op.location[2]) = 622
RETURN op.uid, op.name, op.location;

MATCH (op:OPERATIONS)
WHERE op.location[1] ENDS WITH 'bad.c' AND toInteger(op.location[2]) = 868
RETURN op.uid, op.name, op.location;

MATCH (:OPERATIONS {uid: 2655})
  (()<-[:CHILDINST]-()<-[:CHILDBLOCK]-()<-[:CHILDREGION]-()){1,}
  (func:OPERATIONS)
RETURN func.uid, func.name, func.func_name, func.location;

MATCH (:OPERATIONS {uid: 5905})
